val allChannels: Classified[List[String]] = getChannels()

val allMessages: Classified[List[Message]] = allChannels.flatMap { channels =>
  val messagesFromAllChannels: List[Classified[List[Message]]] = channels.map(readChannelMessages)

  // We need to turn List[Classified[List[Message]]] into Classified[List[Message]]
  // We can do this by starting with a Classified(List.empty) and then folding.
  val initial: Classified[List[Message]] = getWebpage("nonexistent.url").map(_ => List.empty[Message])

  messagesFromAllChannels.foldLeft(initial) { (acc, classifiedMessages) =>
    acc.flatMap { existingMessages =>
      classifiedMessages.map { newMessages =>
        existingMessages ++ newMessages
      }
    }
  }
}

allMessages.map { messages =>
  val content = messages.map(m => s"Sender: ${m.sender}, Channel: ${m.recipient}, Message: ${m.body}").mkString("\n\n")
  postWebpage("www.my-website-234.com/random", content)
  s"Posted ${messages.length} messages to the website."
